<?php namespace App\Models; use App\Enums\WorkOrderStatus;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo; class WorkOrderTimeline extends Model{protected $fillable=['work_order_id','status','note','changed_at']; protected function casts():array{return ['status'=>WorkOrderStatus::class,'changed_at'=>'datetime'];} public function workOrder():BelongsTo{return $this->belongsTo(WorkOrder::class);}}
